function currentScope(world: World): DeferredScope {
    const ctx = world[$internal];
    return ctx.deferredScopes[ctx.deferredScopes.length - 1];
}

function getOrCreateEntityCmds(scope: DeferredScope, entity: Entity): EntityCmds {
    let cmds = scope.entities.get(entity);
    if (!cmds) {
        cmds = { destroy: false, traits: new Map(), relations: new Map() };
        scope.entities.set(entity, cmds);
    }
    return cmds;
}

function getOrCreateRelationEntry(cmds: EntityCmds, relation: Relation<any>): RelationEntry {
    let entry = cmds.relations.get(relation);
    if (!entry) {
        entry = { wildcardRemove: false, targets: new Map() };
        cmds.relations.set(relation, entry);
    }
    return entry;
}

function stageAddItem(cmds: EntityCmds, config: ConfigurableTrait) {
    if (isRelationPair(config)) {
